export function onMount(fn) {
	if (component_context === null) {
		e.lifecycle_outside_component('onMount');
	}

	if (legacy_mode_flag && component_context.l !== null) {
		init_update_callbacks(component_context).m.push(fn);
	} else {
		user_effect(() => {
			const cleanup = untrack(fn);
			if (typeof cleanup === 'function') return /** @type {() => void} */ (cleanup);
		});
	}
}

export function addGetToStores<T extends Record<string, Writable<unknown>>>(stores: T) {
	return Object.keys(stores).reduce(
		(acc, key) => {
			return {
				...acc,
				[key]: withGet(stores[key]),
			};
		},
		{} as {
			[K in keyof T]: WithGet<T[K]>;
		}
	);
}

const item = makeElement(name('item'), {
	stores: value,
	returned: ($value) => {
		return (props: AccordionItemProps) => {
			const { value: itemValue, disabled } = parseItemProps(props);

			return {
				'data-state': isSelected(itemValue, $value) ? 'open' : 'closed',
				'data-disabled': disabledAttr(disabled),
			} as const;
		};
	},
});

export function blur(
	node,
	{ delay = 0, duration = 400, easing = cubic_in_out, amount = 5, opacity = 0 } = {}
) {
	const style = getComputedStyle(node);
	const target_opacity = +style.opacity;
	const f = style.filter === 'none' ? '' : style.filter;
	const od = target_opacity * (1 - opacity);
	const [value, unit] = split_css_unit(amount);
	return {
		delay,
		duration,
		easing,
		css: (_t, u) => `opacity: ${target_opacity - od * u}; filter: ${f} blur(${u * value}${unit});`
	};
}

function mark_eager_effects(value, effects) {
	if (value.reactions === null) return;

	for (const reaction of value.reactions) {
		const flags = reaction.f;

		if ((flags & DERIVED) !== 0) {
			mark_eager_effects(/** @type {Derived} */ (reaction), effects);
		} else if ((flags & EAGER_EFFECT) !== 0) {
			set_signal_status(reaction, DIRTY);
			effects.add(/** @type {Effect} */ (reaction));
		}
	}
}

onkeydown(e: BitsKeyboardEvent): void {
	if (this.#isDisabled) return;

	if (e.key === kbd.SPACE || e.key === kbd.ENTER) {
		e.preventDefault();
		this.itemState.updateValue();
		return;
	}

	this.#root.rovingFocusGroup.handleKeydown(this.opts.ref.current, e);
}

onclick(e: BitsMouseEvent) {
	if (this.opts.disabled.current) return;
	if (e.button > 0) return;
	this.root.handleOpen();
}

onkeydown(e: BitsKeyboardEvent) {
	if (this.opts.disabled.current) return;
	if (e.key === kbd.SPACE || e.key === kbd.ENTER) {
		e.preventDefault();
		this.root.handleOpen();
	}
}

getTabIndex(node: HTMLElement | null | undefined) {
	const items = this.getCandidateNodes();
	const anyActive = this.#currentTabStopId.current !== null;

	if (node && !anyActive && items[0] === node) {
		this.#currentTabStopId.current = node.id;
		return 0;
	} else if (node?.id === this.#currentTabStopId.current) {
		return 0;
	}

	return -1;
}

export function isElseBlockWithElseIf(node: SvelteNode | null | undefined) {
    return (
        !!node &&
        node.type === 'ElseBlock' &&
        'children' in node &&
        Array.isArray(node.children) &&
        node.children.length === 1 &&
        node.children[0].type === 'IfBlock'
    );
}

export function snippet(node, get_snippet, ...args) {
	var branches = new BranchManager(node);

	block(() => {
		const snippet = get_snippet() ?? null;

		if (DEV && snippet == null) {
			e.invalid_snippet();
		}

		branches.ensure(snippet, snippet && ((anchor) => snippet(anchor, ...args)));
	}, EFFECT_TRANSPARENT);
}

function allow_comment_or_whitespace(parser) {
	parser.allow_whitespace();
	while (parser.match('/*') || parser.match('<!--')) {
		if (parser.eat('/*')) {
			parser.read_until(REGEX_COMMENT_CLOSE);
			parser.eat('*/', true);
		}

		if (parser.eat('<!--')) {
			parser.read_until(REGEX_HTML_COMMENT_CLOSE);
			parser.eat('-->', true);
		}

		parser.allow_whitespace();
	}
}

function check_hash(element, server_hash, value) {
	if (!server_hash || server_hash === hash(String(value ?? ''))) return;

	let location;

	// @ts-expect-error
	const loc = element.__svelte_meta?.loc;
	if (loc) {
		location = `near ${loc.file}:${loc.line}:${loc.column}`;
	} else if (dev_current_component_function?.[FILENAME]) {
		location = `in ${dev_current_component_function[FILENAME]}`;
	}

	w.hydration_html_changed(sanitize_location(location));
}

static ensure() {
	if (current_batch === null) {
		const batch = (current_batch = new Batch());

		if (!is_processing && !is_flushing_sync) {
			queue_micro_task(() => {
				if (!batch.#started) {
					batch.flush();
				}
			});
		}
	}

	return current_batch;
}

export function reset(state) {
	dev = false;
	runes = false;
	component_name = UNKNOWN_FILENAME;
	source = '';
	source_lines = [];
	filename = (state.filename ?? UNKNOWN_FILENAME).replace(/\\/g, '/');
	warning_filter = state.warning ?? (() => true);
	warnings = [];
}

function is_supported() {
	if (supported === null) {
		var select = create_element('select');
		select.innerHTML = create_trusted_html('<option><span>t</span></option>');
		supported = /** @type {Element} */ (select.firstChild)?.firstChild?.nodeType === 1;
	}

	return supported;
}

checkIfElementIsScriptTag(node: Node, parent: Node) {
    if (parent !== this.htmlxAst && node.name === 'script') {
        this.topLevelScripts = this.topLevelScripts.filter(
            (tag) => tag.start !== node.start || tag.end !== node.end
        );
    }
}
